import type React from 'react';

import { type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';
import { chipVariants } from './common/variants';

interface ChipOwnProps {
  children: React.ReactNode;
}

type ChipProps = React.ComponentProps<'span'> &
  VariantProps<typeof chipVariants> &
  ChipOwnProps;

/**
 * A presentational chip component for displaying labels and text corraled in a
 * lozenge-shaped container.
 */
function Chip({ children, className, size, ...props }: ChipProps) {
  return (
    <span
      data-slot="chip"
      className={cn(chipVariants({ size }), className)}
      {...props}
    >
      {children}
    </span>
  );
}

export { Chip };
export type { ChipProps };
